cpp.code:
#include <iostream>
#include <stdexcept>
#include <string>

int main() {
    std::string input;
    std::cout << "Введите число: ";
    std::cin >> input;
    try {
        int x = std::stoi(input);
        if (x == 0) throw std::runtime_error("деление на ноль");
        double y = 10.0 / x;
        std::cout << "Результат: " << y << std::endl;
    } catch (const std::invalid_argument& e) {
        std::cout << "Ошибка: введено не число" << std::endl;
    } catch (const std::runtime_error& e) {
        std::cout << "Ошибка: " << e.what() << std::endl;
    } catch (...) {
        std::cout << "Неизвестная ошибка" << std::endl;
    }
    return 0;
}

