cpp.code:
#include <iostream>
#include <fstream>

int main() {
    std::ifstream file("file.txt");
    try {
        if (!file.is_open()) throw std::runtime_error("Файл не найден");
        std::string data;
        std::getline(file, data);
    } catch (const std::exception& e) {
        std::cout << e.what() << std::endl;
    }
    // file автоматически закроется в деструкторе (RAII)
    std::cout << "Ресурс закрыт автоматически" << std::endl;
    return 0;
}

